#include <iostream>

int main() {
    int playerHealth = 45;
    int playerGold = 80;

    std::cout << "=== Player Status ===" << std::endl;

    if (playerHealth > 50) {
        std::cout << "You are feeling strong!" << std::endl;
    } else if (playerHealth >= 20 && playerHealth <= 50) {
        std::cout << "You are wounded, but alive." << std::endl;
    } else {
        std::cout << "You are critically injured!" << std::endl;
    }

    if (playerGold > 50) {
        std::cout << "You have enough money for the potion." << std::endl;
    } else {
        std::cout << "You're too poor for that potion." << std::endl;
    }

    return 0;
}
